package com.trademaster.ims.mobile.orders.model;
import jakarta.persistence.*;import java.time.Instant;
@Entity @Table(name="customer_return_requests",uniqueConstraints={@UniqueConstraint(name="uk_return_number",columnNames="request_number"),@UniqueConstraint(name="uk_return_idempotency",columnNames={"customer_account_id","idempotency_key"})},indexes={@Index(name="idx_return_order",columnList="order_id")})
public class CustomerReturnRequest{public enum Status{REQUESTED,UNDER_REVIEW,APPROVED,PARTIALLY_APPROVED,REJECTED,CANCELLED_BY_CUSTOMER,ITEM_RECEIVED,INSPECTED,RESTOCKED,NON_RESTOCKABLE,REFUND_PENDING,REFUNDED,CLOSED}public enum PreferredResolution{REFUND_REQUESTED,REPLACEMENT_REQUESTED,STORE_CREDIT_REQUESTED}@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(name="request_number",nullable=false,length=40)private String requestNumber;@Column(name="order_id",nullable=false)private Long orderId;@Column(name="customer_account_id",nullable=false)private Long accountId;@Enumerated(EnumType.STRING)@Column(nullable=false,length=35)private Status status=Status.REQUESTED;@Column(name="reason_summary",nullable=false,length=80)private String reasonSummary;@Enumerated(EnumType.STRING)@Column(name="preferred_resolution",nullable=false,length=40)private PreferredResolution preferredResolution;@Column(name="customer_comment",length=500)private String customerComment;@Column(name="idempotency_key",nullable=false,length=100)private String idempotencyKey;@Column(name="requested_at",nullable=false)private Instant requestedAt;@Column(name="updated_at",nullable=false)private Instant updatedAt;@Version private Long version;@PrePersist void p(){Instant n=Instant.now();if(requestedAt==null)requestedAt=n;updatedAt=n;}@PreUpdate void u(){updatedAt=Instant.now();}
public Long getId(){return id;}public String getRequestNumber(){return requestNumber;}public Long getOrderId(){return orderId;}public Long getAccountId(){return accountId;}public Status getStatus(){return status;}public String getReasonSummary(){return reasonSummary;}public PreferredResolution getPreferredResolution(){return preferredResolution;}public String getCustomerComment(){return customerComment;}public String getIdempotencyKey(){return idempotencyKey;}public Instant getRequestedAt(){return requestedAt;}public void setRequestNumber(String v){requestNumber=v;}public void setOrderId(Long v){orderId=v;}public void setAccountId(Long v){accountId=v;}public void setStatus(Status v){status=v;}public void setReasonSummary(String v){reasonSummary=v;}public void setPreferredResolution(PreferredResolution v){preferredResolution=v;}public void setCustomerComment(String v){customerComment=v;}public void setIdempotencyKey(String v){idempotencyKey=v;}public void setRequestedAt(Instant v){requestedAt=v;}}
